export const routes = [
  {
    path: 'customers',
    loadChildren: () => import('@acme/customer-feature'),
  },
];

@Component({ templateUrl: './home.page.html' })
export class HomePage {
  products = inject(ProductDataAccess).featured();
}

@Component({
  selector: 'acme-button',
  template: '<button class="button"><ng-content /></button>',
})
export class ButtonComponent {}

@Component({
  selector: 'acme-table',
  templateUrl: './table.component.html',
})
export class TableComponent<T> {
  rows = input.required<T[]>();
}

export function createApiClient(baseUrl: string) {
  return {
    get: <T>(path: string) => fetch(`${baseUrl}${path}`).then((r) => r.json() as Promise<T>),
  };
}
